(1, '1', '8', 'Gold Core $2500 Per Claim', '10', '\"<h6><strong style=\\\"color: rgba(0, 0, 0, 0.87); background-color: rgb(255, 255, 255);\\\">Gold Core $2500 Per Claim </strong></h6><h6><strong style=\\\"color: rgba(0, 0, 0, 0.87); background-color: rgb(255, 255, 255);\\\">Components Covered</strong></h6><ol><li data-list=\\\"bullet\\\"><span class=\\\"ql-ui\\\" contenteditable=\\\"false\\\"></span><span style=\\\"color: rgba(0, 0, 0, 0.87); background-color: rgb(255, 255, 255);\\\">Powertrain Components Including Sensors, Seals &amp; Gaskets*</span></li><li data-list=\\\"bullet\\\"><span class=\\\"ql-ui\\\" contenteditable=\\\"false\\\"></span><span style=\\\"color: rgba(0, 0, 0, 0.87); background-color: rgb(255, 255, 255);\\\">Air Conditioning</span></li><li data-list=\\\"bullet\\\"><span class=\\\"ql-ui\\\" contenteditable=\\\"false\\\"></span><span style=\\\"color: rgba(0, 0, 0, 0.87); background-color: rgb(255, 255, 255);\\\">Turbo Charger</span></li><li data-list=\\\"bullet\\\"><span class=\\\"ql-ui\\\" contenteditable=\\\"false\\\"></span><span style=\\\"color: rgba(0, 0, 0, 0.87); background-color: rgb(255, 255, 255);\\\">Electronic Ignition</span></li><li data-list=\\\"bullet\\\"><span class=\\\"ql-ui\\\" contenteditable=\\\"false\\\"></span><span style=\\\"color: rgba(0, 0, 0, 0.87); background-color: rgb(255, 255, 255);\\\">Electric System</span></li><li data-list=\\\"bullet\\\"><span class=\\\"ql-ui\\\" contenteditable=\\\"false\\\"></span><span style=\\\"color: rgba(0, 0, 0, 0.87); background-color: rgb(255, 255, 255);\\\">Fuel Injection System</span></li><li data-list=\\\"bullet\\\"><span class=\\\"ql-ui\\\" contenteditable=\\\"false\\\"></span><span style=\\\"color: rgba(0, 0, 0, 0.87); background-color: rgb(255, 255, 255);\\\">Brakes &amp; ABS Brakes</span></li><li data-list=\\\"bullet\\\"><span class=\\\"ql-ui\\\" contenteditable=\\\"false\\\"></span><span style=\\\"color: rgba(0, 0, 0, 0.87); background-color: rgb(255, 255, 255);\\\">Power Steering</span></li></ol><h6><strong style=\\\"color: rgba(0, 0, 0, 0.87); background-color: rgb(255, 255, 255);\\\">Seals &amp; Gaskets on Covered Parts Only</strong></h6><h6><strong style=\\\"color: rgba(0, 0, 0, 0.87); background-color: rgb(255, 255, 255);\\\">Features</strong></h6><ol><li data-list=\\\"bullet\\\"><span class=\\\"ql-ui\\\" contenteditable=\\\"false\\\"></span><strong style=\\\"color: rgba(0, 0, 0, 0.87); background-color: rgb(255, 255, 255);\\\">Select “No Limits Per Claim” </strong><span style=\\\"color: rgba(0, 0, 0, 0.87); background-color: rgb(255, 255, 255);\\\">With a liability cap of $20,000, our Gold Plans offer exceptional coverage.</span></li><li data-list=\\\"bullet\\\"><span class=\\\"ql-ui\\\" contenteditable=\\\"false\\\"></span><strong style=\\\"color: rgba(0, 0, 0, 0.87); background-color: rgb(255, 255, 255);\\\">Quick &amp; Stress-Free Claims Process:</strong><span style=\\\"color: rgba(0, 0, 0, 0.87); background-color: rgb(255, 255, 255);\\\">Get Covered Canada is committed to a fast and seamless claims process, allowing you to select your preferred repair shop.</span></li></ol><h6><strong style=\\\"color: rgba(0, 0, 0, 0.87); background-color: rgb(255, 255, 255);\\\">Coverage for Vehicles Less than 7 Years Old</strong></h6><ol><li data-list=\\\"bullet\\\"><span class=\\\"ql-ui\\\" contenteditable=\\\"false\\\"></span><span style=\\\"color: rgba(0, 0, 0, 0.87); background-color: rgb(255, 255, 255);\\\">We provide tailored plans for new or used vehicles of any age. Speak with one of our Customer Service Associates to find the right coverage for your vehicle</span></li></ol>\"', '[{\"productName\":\"60 Months/10500 KM\",\"productPrice\":\"1099\"},{\"productName\":\"48 Months/85000 KM\",\"productPrice\":\"949\"},{\"productName\":\"36 Months/65000 KM\",\"productPrice\":\"789\"},{\"productName\":\"28 Months/50000 KM\",\"productPrice\":\"715\"},{\"productName\":\"12 Months/25000 KM\",\"productPrice\":\"465\"}]', './Images/1736683808003.pdf'),
