(22, '6', '15', 'Max Liability: $7500 Financed Amt:$0 - $75000', '25', '\"<p><strong>GAP Financial Protection Bundle - Max Liability: $7500 - Financed Amt: $0 - $75,000 </strong></p><p><strong>Components Covered:</strong></p><p><strong>The GCC Financial GAP Bundle Protects You Against The Unexpected</strong></p><p><strong>FINANCIAL GAP BUNDLE Protects You in the case of a TOTAL LOSS Due To:</strong></p><ol><li data-list=\\\"bullet\\\" class=\\\"ql-indent-1\\\"><span class=\\\"ql-ui\\\" contenteditable=\\\"false\\\"></span><strong>ACCIDENT</strong></li><li data-list=\\\"bullet\\\" class=\\\"ql-indent-1\\\"><span class=\\\"ql-ui\\\" contenteditable=\\\"false\\\"></span><strong>THEFT</strong></li><li data-list=\\\"bullet\\\" class=\\\"ql-indent-1\\\"><span class=\\\"ql-ui\\\" contenteditable=\\\"false\\\"></span><strong>FIRE</strong></li><li data-list=\\\"bullet\\\" class=\\\"ql-indent-1\\\"><span class=\\\"ql-ui\\\" contenteditable=\\\"false\\\"></span><strong>VANDALISM</strong></li><li data-list=\\\"bullet\\\" class=\\\"ql-indent-1\\\"><span class=\\\"ql-ui\\\" contenteditable=\\\"false\\\"></span><strong>FLOOD OR WEATHER DAMAGE </strong></li></ol><p><strong>Collision Deductible:</strong></p><ol><li data-list=\\\"bullet\\\" class=\\\"ql-indent-1\\\"><span class=\\\"ql-ui\\\" contenteditable=\\\"false\\\"></span><strong>Reimburses Your Deductible Payment For At-Fault Auto Collision Claim</strong></li><li data-list=\\\"bullet\\\" class=\\\"ql-indent-1\\\"><span class=\\\"ql-ui\\\" contenteditable=\\\"false\\\"></span><strong>Max of $1000* </strong></li></ol><p><strong>$500 Loyalty Credit:</strong></p><ol><li data-list=\\\"bullet\\\" class=\\\"ql-indent-1\\\"><span class=\\\"ql-ui\\\" contenteditable=\\\"false\\\"></span><strong>Buy Your Replacement Vehicle from the Same Dealer and Receive $500 Towards the Purchase </strong></li></ol><p><strong>Mechanical Breakdown Protection:</strong></p><ol><li data-list=\\\"bullet\\\" class=\\\"ql-indent-1\\\"><span class=\\\"ql-ui\\